CREATE DATABASE IF NOT EXISTS `cekdulu` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `cekdulu`;
SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS `article_product`,`articles`,`affiliate_clicks`,`affiliate_links`,`product_prices`,`product_images`,`products`,`marketplaces`,`brands`,`categories`,`users`;
CREATE TABLE `users`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`name` VARCHAR(255) NOT NULL,`email` VARCHAR(255) NOT NULL UNIQUE,`email_verified_at` TIMESTAMP NULL,`password` VARCHAR(255) NOT NULL,`remember_token` VARCHAR(100) NULL,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `categories`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`name` VARCHAR(255) NOT NULL,`slug` VARCHAR(255) NOT NULL UNIQUE,`icon` VARCHAR(255) NULL,`description` TEXT NULL,`is_active` TINYINT(1) NOT NULL DEFAULT 1,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `brands`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`name` VARCHAR(255) NOT NULL,`slug` VARCHAR(255) NOT NULL UNIQUE,`logo` VARCHAR(255) NULL,`description` TEXT NULL,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `marketplaces`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`name` VARCHAR(255) NOT NULL,`slug` VARCHAR(255) NOT NULL UNIQUE,`logo` VARCHAR(255) NULL,`base_url` VARCHAR(255) NULL,`is_active` TINYINT(1) NOT NULL DEFAULT 1,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `products`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`category_id` BIGINT UNSIGNED NULL,`brand_id` BIGINT UNSIGNED NULL,`name` VARCHAR(255) NOT NULL,`slug` VARCHAR(255) NOT NULL UNIQUE,`short_description` TEXT NULL,`description` LONGTEXT NULL,`specifications` JSON NULL,`pros` JSON NULL,`cons` JSON NULL,`thumbnail` VARCHAR(255) NULL,`worth_it_score` TINYINT UNSIGNED NOT NULL DEFAULT 70,`admin_score_adjustment` INT NOT NULL DEFAULT 0,`lowest_price` BIGINT UNSIGNED NULL,`status` ENUM('draft','published','archived') NOT NULL DEFAULT 'draft',`is_featured` TINYINT(1) NOT NULL DEFAULT 0,`is_trending` TINYINT(1) NOT NULL DEFAULT 0,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`),KEY(`category_id`),KEY(`brand_id`),KEY(`status`),CONSTRAINT `products_category_fk` FOREIGN KEY(`category_id`) REFERENCES `categories`(`id`) ON DELETE SET NULL,CONSTRAINT `products_brand_fk` FOREIGN KEY(`brand_id`) REFERENCES `brands`(`id`) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `product_images`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`product_id` BIGINT UNSIGNED NOT NULL,`image_url` VARCHAR(255) NOT NULL,`sort_order` INT NOT NULL DEFAULT 0,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`),CONSTRAINT `product_images_product_fk` FOREIGN KEY(`product_id`) REFERENCES `products`(`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `product_prices`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`product_id` BIGINT UNSIGNED NOT NULL,`marketplace_id` BIGINT UNSIGNED NOT NULL,`seller_name` VARCHAR(255) NULL,`product_url` TEXT NOT NULL,`price` BIGINT UNSIGNED NOT NULL,`original_price` BIGINT UNSIGNED NULL,`discount` VARCHAR(255) NULL,`rating` DECIMAL(3,2) NULL,`sold_count` INT UNSIGNED NOT NULL DEFAULT 0,`review_count` INT UNSIGNED NOT NULL DEFAULT 0,`is_recommended` TINYINT(1) NOT NULL DEFAULT 0,`last_updated_at` TIMESTAMP NULL,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`),KEY(`product_id`),KEY(`marketplace_id`),CONSTRAINT `product_prices_product_fk` FOREIGN KEY(`product_id`) REFERENCES `products`(`id`) ON DELETE CASCADE,CONSTRAINT `product_prices_marketplace_fk` FOREIGN KEY(`marketplace_id`) REFERENCES `marketplaces`(`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `affiliate_links`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`product_id` BIGINT UNSIGNED NOT NULL,`marketplace_id` BIGINT UNSIGNED NOT NULL,`product_price_id` BIGINT UNSIGNED NULL,`affiliate_url` TEXT NOT NULL,`campaign_name` VARCHAR(255) NULL,`is_active` TINYINT(1) NOT NULL DEFAULT 1,`click_count` INT UNSIGNED NOT NULL DEFAULT 0,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`),KEY(`product_id`),KEY(`marketplace_id`),KEY(`product_price_id`),CONSTRAINT `affiliate_product_fk` FOREIGN KEY(`product_id`) REFERENCES `products`(`id`) ON DELETE CASCADE,CONSTRAINT `affiliate_marketplace_fk` FOREIGN KEY(`marketplace_id`) REFERENCES `marketplaces`(`id`) ON DELETE CASCADE,CONSTRAINT `affiliate_price_fk` FOREIGN KEY(`product_price_id`) REFERENCES `product_prices`(`id`) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `affiliate_clicks`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`affiliate_link_id` BIGINT UNSIGNED NOT NULL,`product_id` BIGINT UNSIGNED NULL,`marketplace_id` BIGINT UNSIGNED NULL,`ip_address` VARCHAR(45) NULL,`user_agent` TEXT NULL,`referrer` TEXT NULL,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`),CONSTRAINT `click_link_fk` FOREIGN KEY(`affiliate_link_id`) REFERENCES `affiliate_links`(`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `articles`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`user_id` BIGINT UNSIGNED NULL,`title` VARCHAR(255) NOT NULL,`slug` VARCHAR(255) NOT NULL UNIQUE,`excerpt` TEXT NULL,`content` LONGTEXT NULL,`featured_image` VARCHAR(255) NULL,`seo_title` VARCHAR(255) NULL,`meta_description` TEXT NULL,`status` ENUM('draft','published','archived') NOT NULL DEFAULT 'draft',`published_at` TIMESTAMP NULL,`created_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,`updated_at` TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE `article_product`(`id` BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,`article_id` BIGINT UNSIGNED NOT NULL,`product_id` BIGINT UNSIGNED NOT NULL,PRIMARY KEY(`id`),UNIQUE KEY `article_product_unique`(`article_id`,`product_id`),CONSTRAINT `article_product_article_fk` FOREIGN KEY(`article_id`) REFERENCES `articles`(`id`) ON DELETE CASCADE,CONSTRAINT `article_product_product_fk` FOREIGN KEY(`product_id`) REFERENCES `products`(`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
