INSERT INTO `products` (`id`,`category_id`,`brand_id`,`name`,`slug`,`short_description`,`description`,`specifications`,`pros`,`cons`,`worth_it_score`,`lowest_price`,`status`,`is_featured`,`is_trending`) VALUES (1,1,1,'ASUS ROG Zephyrus G14 2025','asus-rog-zephyrus-g14-2025','Laptop gaming ringkas dengan performa tinggi.','ASUS ROG Zephyrus G14 cocok untuk gamer, editor, dan pekerja kreatif.','{"Processor":"AMD Ryzen 9","GPU":"RTX 4060","RAM":"16GB","Storage":"1TB SSD"}','["Performa kuat","Layar bagus"]','["Harga tinggi"]',93,17499000,'published',1,1),(2,1,2,'Lenovo Legion 5i Gen 9 RTX 4060','lenovo-legion-5i-gen-9-rtx-4060','Laptop gaming value for money.','Lenovo Legion 5i menawarkan performa gaming stabil dan harga kompetitif.','{"Processor":"Intel Core i7","GPU":"RTX 4060","RAM":"16GB"}','["Cooling bagus","Harga kompetitif"]','["Bobot berat"]',91,14999000,'published',1,1),(3,3,3,'Sony WH-1000XM5 ANC','sony-wh-1000xm5-anc','Headphone ANC premium.','Sony WH-1000XM5 adalah headphone over-ear flagship dengan noise cancelling terbaik.','{"Driver":"30mm","ANC":"Yes","Battery":"30 hours"}','["ANC bagus","Suara premium"]','["Harga tinggi"]',95,3099000,'published',1,1),(4,4,4,'Keychron Q1 Pro Wireless','keychron-q1-pro-wireless','Mechanical keyboard premium wireless.','Keychron Q1 Pro cocok untuk enthusiast keyboard.','{"Switch":"Hot-swap","Connection":"Wireless"}','["Build solid"]','["Berat"]',91,1850000,'published',1,0),(5,2,5,'Samsung Galaxy S25 Ultra 256GB','samsung-galaxy-s25-ultra-256gb','Smartphone flagship Android.','Samsung Galaxy S25 Ultra cocok untuk kamera dan performa.','{"Storage":"256GB","RAM":"12GB"}','["Kamera bagus"]','["Harga mahal"]',88,14999000,'published',1,1),(6,5,6,'LG 27GP850-B 165Hz IPS Gaming','lg-27gp850-b-165hz-ips-gaming','Monitor gaming IPS 165Hz.','Monitor LG cocok untuk gaming dan kerja harian.','{"Size":"27 inch","Panel":"IPS","Refresh Rate":"165Hz"}','["Panel IPS bagus"]','["Stand besar"]',90,3750000,'published',1,0);
