INSERT INTO `articles` (`id`,`user_id`,`title`,`slug`,`excerpt`,`content`,`seo_title`,`meta_description`,`status`,`published_at`) VALUES (1,1,'Laptop Gaming 10 Jutaan Terbaik','laptop-gaming-10-jutaan-terbaik','Rekomendasi laptop gaming worth it.','<p>Memilih laptop gaming tidak harus selalu mahal. Fokus utama adalah performa GPU, cooling, kualitas layar, dan harga yang masuk akal.</p>','Laptop Gaming 10 Jutaan Terbaik - CekDulu','Rekomendasi laptop gaming 10 jutaan paling worth it.','published',NOW()),(2,1,'Mending Beli Headphone ANC atau TWS?','mending-headphone-anc-atau-tws','Perbandingan headphone ANC dan TWS.','<p>Headphone ANC cocok untuk fokus dan perjalanan jauh, sedangkan TWS lebih praktis untuk mobilitas harian.</p>','Mending Headphone ANC atau TWS?','Perbandingan headphone ANC dan TWS.','published',NOW());
SET FOREIGN_KEY_CHECKS=1;
